const body = $('Receive Audit Submission').item.json.body;
const claudeResponse = $input.item.json;
const reportText = claudeResponse.content[0].text;

// Parse sections
const extract = (tag) => {
  const re = new RegExp(`\\[${tag}\\]([\\s\\S]*?)(?=\\[|$)`);
  const m = reportText.match(re);
  return m ? m[1].trim() : '';
};

const execSummary = extract('EXECUTIVE_SUMMARY');
const strengthsGaps = extract('STRENGTHS_GAPS');
const actionPlanRaw = extract('ACTION_PLAN');
const quickWins = extract('QUICK_WINS');

// Parse action plan
const actionLines = actionPlanRaw.split('\n').filter(l => l.includes('|'));
const actionsHTML = actionLines.map(line => {
  const [p, title, desc, tag] = line.split('|');
  if (!p || !title) return '';
  const color = p.trim() === 'HIGH' ? '#b5291c' : p.trim() === 'MED' ? '#8a5a00' : '#1e6e45';
  const bg = p.trim() === 'HIGH' ? '#fdf0ee' : p.trim() === 'MED' ? '#fdf5e6' : '#eef6f1';
  return `
    <tr>
      <td style="padding:14px 20px;border-bottom:1px solid #e8e4dc;vertical-align:top;">
        <span style="display:inline-block;background:${bg};color:${color};font-family:monospace;font-size:10px;padding:2px 8px;border-radius:2px;margin-bottom:6px;">${p.trim()}</span><br/>
        <strong style="font-size:13px;color:#1c1814;">${(title||'').trim()}</strong><br/>
        <span style="font-size:12px;color:#7a6e62;line-height:1.6;">${(desc||'').trim()}</span><br/>
        <span style="font-family:monospace;font-size:10px;color:#b0a898;border:1px solid #ddd8cf;padding:1px 6px;border-radius:2px;display:inline-block;margin-top:4px;">${(tag||'').trim()}</span>
      </td>
    </tr>`;
}).join('');

// Category bars
const scores = body.scores || {};
const categories = [
  { name: 'Operations & Workflows', icon: '⚙️', key: 'operations' },
  { name: 'Sales & Lead Management', icon: '📈', key: 'sales' },
  { name: 'Customer Experience', icon: '💬', key: 'customer' },
  { name: 'Marketing & Content', icon: '📣', key: 'marketing' },
  { name: 'Strategy & AI Readiness', icon: '🧠', key: 'strategy' }
];

const catBarsHTML = categories.map(cat => {
  const pct = scores[cat.key] || 0;
  const color = pct >= 75 ? '#27ae60' : pct >= 50 ? '#8a5a00' : '#b5291c';
  return `
    <tr>
      <td style="padding:10px 20px;border-bottom:1px solid #f0ece4;">
        <table width="100%" cellpadding="0" cellspacing="0">
          <tr>
            <td style="font-size:12px;font-weight:500;color:#1c1814;width:200px;">${cat.icon} ${cat.name}</td>
            <td style="padding:0 16px;">
              <div style="height:4px;background:#e8e4dc;border-radius:2px;overflow:hidden;">
                <div style="height:4px;width:${pct}%;background:${color};border-radius:2px;"></div>
              </div>
            </td>
            <td style="font-family:monospace;font-size:11px;color:#7a6e62;width:36px;text-align:right;">${pct}%</td>
          </tr>
        </table>
      </td>
    </tr>`;
}).join('');

// Tier color
const score = body.totalScore || 0;
const tierLabel = body.tier || 'Developing';
const tierColor = score >= 75 ? '#27ae60' : score >= 50 ? '#8a5a00' : score >= 25 ? '#b5291c' : '#b5291c';
const tierBg = score >= 75 ? '#eef6f1' : score >= 50 ? '#fdf5e6' : '#fdf0ee';

// Build full HTML email
const emailHTML = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"/></head>
<body style="margin:0;padding:0;background:#f7f4ef;font-family:'Georgia',serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f7f4ef;padding:32px 16px;">
  <tr><td align="center">
    <table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;">

      <!-- HEADER -->
      <tr><td style="background:#1c1814;padding:28px 36px;border-radius:3px 3px 0 0;">
        <p style="margin:0;font-family:monospace;font-size:10px;letter-spacing:0.15em;text-transform:uppercase;color:rgba(255,255,255,0.4);">AI Readiness Report · ${new Date().toLocaleDateString('en-GB',{day:'numeric',month:'long',year:'numeric'})}</p>
        <h1 style="margin:12px 0 4px;font-size:28px;font-weight:700;color:#fff;letter-spacing:-0.02em;">${body.bizName || 'Your Business'}</h1>
        <p style="margin:0 0 24px;font-size:13px;color:rgba(255,255,255,0.5);">${body.bizIndustry || ''} · ${body.bizSize || ''}</p>
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="font-size:64px;font-weight:700;color:#fff;line-height:1;letter-spacing:-0.04em;">${score}</td>
            <td style="font-size:20px;color:rgba(255,255,255,0.3);padding:0 4px 8px;font-family:monospace;">/100</td>
            <td style="padding:0 0 8px 16px;">
              <p style="margin:0 0 6px;font-family:monospace;font-size:10px;letter-spacing:0.1em;text-transform:uppercase;color:rgba(255,255,255,0.4);">AI Readiness Score</p>
              <span style="display:inline-block;background:${tierBg};color:${tierColor};font-size:12px;font-weight:600;padding:4px 12px;border-radius:2px;">${tierLabel}</span>
            </td>
          </tr>
        </table>
      </td></tr>

      <!-- CATEGORY SCORES -->
      <tr><td style="background:#fff;border-left:1px solid #ddd8cf;border-right:1px solid #ddd8cf;">
        <table width="100%" cellpadding="0" cellspacing="0">
          <tr><td style="padding:20px 20px 8px;"><p style="margin:0;font-family:monospace;font-size:10px;letter-spacing:0.18em;text-transform:uppercase;color:#b0a898;">Category Breakdown</p></td></tr>
          ${catBarsHTML}
        </table>
      </td></tr>

      <!-- EXECUTIVE SUMMARY -->
      <tr><td style="background:#fff;padding:0;border-left:1px solid #ddd8cf;border-right:1px solid #ddd8cf;border-top:1px solid #f0ece4;">
        <table width="100%" cellpadding="0" cellspacing="0">
          <tr><td style="padding:20px 20px 12px;"><p style="margin:0;font-family:monospace;font-size:10px;letter-spacing:0.18em;text-transform:uppercase;color:#b0a898;">Executive Summary</p></td></tr>
          <tr><td style="padding:0 20px 20px;"><div style="border-left:3px solid #1c1814;padding:14px 18px;background:#faf8f4;font-size:14px;line-height:1.8;color:#7a6e62;">${execSummary}</div></td></tr>
        </table>
      </td></tr>

      <!-- STRENGTHS & GAPS -->
      <tr><td style="background:#fff;padding:0;border-left:1px solid #ddd8cf;border-right:1px solid #ddd8cf;border-top:1px solid #f0ece4;">
        <table width="100%" cellpadding="0" cellspacing="0">
          <tr><td style="padding:20px 20px 12px;"><p style="margin:0;font-family:monospace;font-size:10px;letter-spacing:0.18em;text-transform:uppercase;color:#b0a898;">Strengths & Critical Gaps</p></td></tr>
          <tr><td style="padding:0 20px 20px;"><div style="border-left:3px solid #1c1814;padding:14px 18px;background:#faf8f4;font-size:14px;line-height:1.8;color:#7a6e62;white-space:pre-line;">${strengthsGaps}</div></td></tr>
        </table>
      </td></tr>

      <!-- ACTION PLAN -->
      <tr><td style="background:#fff;padding:0;border-left:1px solid #ddd8cf;border-right:1px solid #ddd8cf;border-top:1px solid #f0ece4;">
        <table width="100%" cellpadding="0" cellspacing="0">
          <tr><td style="padding:20px 20px 12px;"><p style="margin:0;font-family:monospace;font-size:10px;letter-spacing:0.18em;text-transform:uppercase;color:#b0a898;">Priority Action Plan</p></td></tr>
          ${actionsHTML}
        </table>
      </td></tr>

      <!-- QUICK WINS -->
      <tr><td style="background:#fff;padding:0;border-left:1px solid #ddd8cf;border-right:1px solid #ddd8cf;border-top:1px solid #f0ece4;">
        <table width="100%" cellpadding="0" cellspacing="0">
          <tr><td style="padding:20px 20px 12px;"><p style="margin:0;font-family:monospace;font-size:10px;letter-spacing:0.18em;text-transform:uppercase;color:#b0a898;">Quick Wins — This Week</p></td></tr>
          <tr><td style="padding:0 20px 20px;"><div style="border-left:3px solid #1c1814;padding:14px 18px;background:#faf8f4;font-size:14px;line-height:1.8;color:#7a6e62;white-space:pre-line;">${quickWins}</div></td></tr>
        </table>
      </td></tr>

      <!-- CTA -->
      <tr><td style="background:#fdf0ee;padding:28px 36px;border:1px solid #ddd8cf;border-top:none;">
        <p style="margin:0 0 6px;font-family:monospace;font-size:10px;letter-spacing:0.15em;text-transform:uppercase;color:#b5291c;">Ready to act on this?</p>
        <h2 style="margin:0 0 10px;font-size:20px;font-weight:700;color:#1c1814;">Need help implementing these recommendations?</h2>
        <p style="margin:0 0 20px;font-size:13px;color:#7a6e62;line-height:1.7;">Book a free 30-minute strategy call. We'll review your audit results together and map out exactly where automation can save you the most time and money.</p>
        <a href="https://calendly.com/sonwa/consultation" style="display:inline-block;background:#b5291c;color:#fff;font-size:13px;font-weight:600;padding:12px 24px;border-radius:2px;text-decoration:none;">Book Your Free Strategy Call →</a>
        <p style="margin:12px 0 0;font-family:monospace;font-size:10px;color:#b0a898;">No commitment. No pitch. Just a focused 30-minute session on your business.</p>
      </td></tr>

      <!-- FOOTER -->
      <tr><td style="padding:20px 36px;background:#f7f4ef;">
        <p style="margin:0;font-family:monospace;font-size:10px;color:#b0a898;text-align:center;">AuditAI · AI Business Intelligence · Powered by Claude</p>
      </td></tr>

    </table>
  </td></tr>
</table>
</body>
</html>`;

return { emailHTML, reportText, email: body.email, bizName: body.bizName, score: body.totalScore, tier: body.tier };
